python3 << 'ENDSCRIPT'
import base64, os, zipfile
d = os.path.expanduser("~/Desktop")
files = {}
files["kinetic-theme/style.css"] = ""
files["kinetic-theme/functions.php"] = ""
files["kinetic-theme/header.php"] = ""
files["kinetic-theme/footer.php"] = ""
files["kinetic-theme/front-page.php"] = ""
files["kinetic-theme/index.php"] = ""
files["kinetic-theme/single.php"] = ""
files["kinetic-theme/page.php"] = ""
files["kinetic-theme/404.php"] = ""
files["kinetic-theme/inc/customizer.php"] = ""
files["kinetic-theme/assets/css/kinetic.css"] = ""
files["kinetic-theme/assets/js/kinetic.js"] = ""
files["kinetic-theme/template-parts/sections/hero.php"] = ""
files["kinetic-theme/template-parts/sections/features.php"] = ""
files["kinetic-theme/template-parts/sections/testimonials.php"] = ""
files["kinetic-theme/template-parts/sections/newsletter.php"] = ""

zpath = os.path.join(d, "kinetic-theme.zip")
import zipfile
with zipfile.ZipFile(zpath, "w", zipfile.ZIP_DEFLATED) as zf:
    for rel, b64 in files.items():
        zf.writestr(rel, base64.b64decode(b64))
print("\n✅ kinetic-theme.zip saved to your Desktop!")
print("Install: WP Admin → Appearance → Themes → Add New → Upload Theme")

